// frontend/src/services/api.js
const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const api = {
    // Generic request method with auth
    async request(endpoint, options = {}) {
        const token = localStorage.getItem('token');
        
        const headers = {
            'Content-Type': 'application/json',
            ...options.headers
        };
        
        if (token) {
            headers['Authorization'] = `Bearer ${token}`;
        }

        const response = await fetch(`${API_URL}${endpoint}`, {
            ...options,
            headers
        });

        const data = await response.json();

        if (!response.ok) {
            // Handle unauthorized (token expired)
            if (response.status === 401) {
                localStorage.removeItem('token');
                localStorage.removeItem('role');
                localStorage.removeItem('email');
                window.location.href = '/auth';
            }
            throw new Error(data.error || 'Request failed');
        }

        return data;
    },

    // ============ AUTH ENDPOINTS ============
    async signUp(data) {
        const response = await this.request('/auth/signup', {
            method: 'POST',
            body: JSON.stringify(data)
        });
        
        // Store the response with user data
        return {
            token: response.token,
            budgeter: {
                id: response.user?.id || response.budgeter?.id,
                email: response.user?.email || response.budgeter?.email,
                full_name: response.user?.full_name || response.budgeter?.full_name,
                role: response.user?.role || response.budgeter?.role || 'user',
                is_verified: response.user?.is_verified || response.budgeter?.is_verified || false,
                is_active: response.user?.is_active !== undefined ? response.user.is_active : true,
                currency: response.user?.currency || response.budgeter?.currency || 'KES'
            }
        };
    },

    async signIn(data) {
        const response = await this.request('/auth/signin', {
            method: 'POST',
            body: JSON.stringify(data)
        });
        
        // Return standardized response with user data
        return {
            token: response.token,
            budgeter: {
                id: response.user?.id || response.budgeter?.id,
                email: response.user?.email || response.budgeter?.email,
                full_name: response.user?.full_name || response.budgeter?.full_name,
                role: response.user?.role || response.budgeter?.role || 'user',
                is_verified: response.user?.is_verified || response.budgeter?.is_verified || false,
                is_active: response.user?.is_active !== undefined ? response.user.is_active : true,
                currency: response.user?.currency || response.budgeter?.currency || 'KES'
            }
        };
    },

    // NEW: Request verification
    async requestVerification(email) {
        return this.request('/auth/request-verification', {
            method: 'POST',
            body: JSON.stringify({ email })
        });
    },

    // NEW: Verify user with token
    async verifyUser(token) {
        return this.request('/auth/verify', {
            method: 'POST',
            body: JSON.stringify({ token })
        });
    },

    // NEW: Check if user is active
    async checkUserStatus(email) {
        return this.request(`/auth/check-status?email=${encodeURIComponent(email)}`);
    },

    getCurrentUser() {
        return this.request('/auth/me');
    },

    logout() {
        localStorage.removeItem('token');
        localStorage.removeItem('role');
        localStorage.removeItem('email');
        return this.request('/auth/logout', { method: 'POST' });
    },

    // ============ EXPENSE ENDPOINTS ============
    getExpenses(params = {}) {
        const query = new URLSearchParams(params).toString();
        return this.request(`/expenses${query ? '?' + query : ''}`);
    },

    createExpense(data) {
        return this.request('/expenses', {
            method: 'POST',
            body: JSON.stringify(data)
        });
    },

    getExpense(id) {
        return this.request(`/expenses/${id}`);
    },

    updateExpense(id, data) {
        return this.request(`/expenses/${id}`, {
            method: 'PUT',
            body: JSON.stringify(data)
        });
    },

    deleteExpense(id) {
        return this.request(`/expenses/${id}`, {
            method: 'DELETE'
        });
    },

    getExpenseSummary(month) {
        return this.request(`/expenses/summary?month=${month}`);
    },

    // ============ INCOME ENDPOINTS ============
    getIncomes(params = {}) {
        const query = new URLSearchParams(params).toString();
        return this.request(`/income${query ? '?' + query : ''}`);
    },

    getIncome(params = {}) {
        return this.getIncomes(params);
    },

    createIncome(data) {
        return this.request('/income', {
            method: 'POST',
            body: JSON.stringify(data)
        });
    },

    getIncomeById(id) {
        return this.request(`/income/${id}`);
    },

    updateIncome(id, data) {
        return this.request(`/income/${id}`, {
            method: 'PUT',
            body: JSON.stringify(data)
        });
    },

    deleteIncome(id) {
        return this.request(`/income/${id}`, {
            method: 'DELETE'
        });
    },

    getIncomeSummary(month) {
        return this.request(`/income/summary?month=${month}`);
    },

    // ============ TRANSACTION ENDPOINTS ============
    addExpense(data) {
    return this.request('/transactions/expense', {
        method: 'POST',
        body: JSON.stringify(data)
    });
},

addIncome(data) {
    return this.request('/transactions/income', {
        method: 'POST',
        body: JSON.stringify(data)
    });
},

getTransactions(params = {}) {
    const query = new URLSearchParams(params).toString();
    return this.request(`/transactions${query ? '?' + query : ''}`);
},

getTransactionExpenses(params = {}) {
