},

getUncategorized() {
    return this.request('/transactions/uncategorized');
},

categorizeTransaction(id, category) {
    return this.request(`/transactions/${id}/categorize`, {
        method: 'PUT',
        body: JSON.stringify({ category })
    });
},

getTransaction(id) {
